mapper.select:
select a.ID,a.TYPE,a.CARGO_INFO_ID,a.TRUST_ID,a.TRUST_CARGO_ID,a.SHIPVOYAGE_ID,a.SHIPVOYAGE_ITEM_ID,a.SHIP_NAME,a.TRADE_TYPE, a.LOAD_UNLOAD,a.CARGO_OWNER_ID,a.CARGO_OWNER_NAME,a.CARGO_AGENT_ID,a.CARGO_AGENT_NAME,a.CARGO_CODE,a.CARGO_NAME, a.QUANTITY,a.TON,a.TICKET_NUM,a.STATEMENT_STATUS_CODE,a.STATEMENT_STATUS_NAME,a.REMARK,a.CREATE_BY,a.CREATE_BY_NAME, a.CREATE_TIME,a.UPDATE_BY,a.UPDATE_BY_NAME,a.UPDATE_TIME,a.VOYAGE,b.company_id,b.COMPANY_NAME,a.SHIP_NAME||'_'||a.VOYAGE AS SHIP_VOYAGE_NAME, b.IS_CLEAR, DECODE(MC.WORK_TYPE, '1', '件杂','2' ,'散杂','3','木材') workType
from T_BUS_HANDOVERLIST a inner join T_BUS_CARGO_INFO b on a.CARGO_INFO_ID=b.ID LEFT JOIN M_CARGO MC ON a.CARGO_CODE = MC.CARGO_CODE
and a.SHIPVOYAGE_ITEM_ID=#{shipvoyageItemId}
and a.CARGO_OWNER_ID=#{cargoOwnerId}
order by id desc

select a.ID,a.CONTACT_NO,a.PARENT_ID,a.CUSTOMER_ID,a.CUSTOMER_NAME,a.SIGN_TIME,a.CONTRACT_TYPE,a.IS_SHIP,a.SETTLEMENT_BASIS_CODE, a.SETTLEMENT_BASIS_NAME,a.DEPOSIT_BASIS_CODE,a.DEPOSIT_BASIS_NAME,a.DEPOSIT_RATIO,a.PAY_TYPE,a.FREE_STORAGE_DAYS, a.START_TIME,a.END_TIME,a.SHIPVOYAGE_ID,a.VALID_BY,a.VALID_BY_NAME,a.VALID_TIME,a."STATUS",a.REMARK,a.COMPANY_NAMES from T_BUS_CONTRACT a inner join T_BUS_CONTRACT_COMPANY b on a.ID=b.CONTRACT_ID
customer_id=#{customerId} and sysdate between START_TIME and END_TIME and status='20' and b.company_id=#{companyId}
order by create_time

select
    ID,CONTRACT_ID,CARGO_CODE,CARGO_NAME,RATE_ITEM_CODE,RATE_ITEM_NAME,TRADE_TYPE,SERVICE_CONTENT_ID,SERVICE_CONTENT_NAME,
    PAYMENT_TYPE_CODE,PAYMENT_TYPE_NAME,PAYMENT_DAYS,RATE,TAX,UNIT_CODE,UNIT_NAME,RATE_ID
from
    t_bus_contract_rate

    contract_id=#{contractId}

        and cargo_code=#{cargoCode}



        and RATE_ITEM_CODE=#{rateItemCode}


order by
    id

SELECT TSFH.ID, TSFH.CARGO_INFO_ID, TSFH.START_DATE, TSFH.END_DATE, TSFH.AMOUNT, TSFH.BALANCES_AMOUNT, TSFH.TOTAL_ENTRY, TSFH.TOTAL_APPEARANCE, TSFH.SETTLEMENT_DAYS, TSFH.FREE_STORAGE_DAYS, TSFH.CREATE_BY, TSFH.CREATE_TIME, TSFH.CREATE_BY_NAME, TSFH.TAX_RATE, TSFH.TAX_CAST, TSFH.AFTER_TAX, TSFH.CONTRACT_ID, TSFH.STATUS, TSFH.RATE, TSFH.IS_FINAL, TCS.STATUS STATEMENT_STATUS FROM T_STORAGE_FEE_HIS TSFH LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TSFH.ID = TCSD.BUSINESS_ID LEFT JOIN T_COST_STATEMENT TCS ON TCSD.STATEMENT = TCS.ID WHERE TSFH.CARGO_INFO_ID=#{cargoInfoId}
AND TSFH.id<#{hisGid,jdbcType=BIGINT}
ORDER BY TSFH.ID desc

mapper.update:
update
    T_STORAGE_FEE_HIS
SET
    STATUS=#{status}
WHERE
    ID=#{id}

mapper.select:
SELECT ID, STATEMENT
FROM T_COST_STATEMENT_DETAIL
WHERE BUSINESS_ID = #{historyGid, jdbcType=BIGINT}

mapper.update:
UPDATE T_COST_STATEMENT
SET STATUS = #{status, jdbcType=VARCHAR}
WHERE ID = #{id, jdbcType=BIGINT}

UPDATE T_BUS_CARGO_INFO
SET STATEMENT_STATUS_CODE = #{statementStatusCode, jdbcType=VARCHAR},
    STATEMENT_STATUS_NAME = #{statementStatusName, jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=BIGINT}
